  1→/**
  2→ * ProjectRepository - CRUD operations for Project model
  3→ *
  4→ * Provides typed methods for Project queries with soft-delete support.
  5→ * Handles Project stage transitions and member management.
  6→ */
  7→
  8→import { prisma } from './prisma';
  9→import type {
 10→  Project,
 11→  ProjectMember,
 12→  ProjectStage,
 13→  Prisma,
 14→} from '@prisma/client';
 15→import { randomUUID } from 'node:crypto';
 16→
 17→/**
 18→ * Project creation input type
 19→ */
 20→export type ProjectCreateInput = Omit<Prisma.ProjectUncheckedCreateInput, 'id' | 'createdAt' | 'updatedAt'>;
 21→
 22→/**
 23→ * Project update input type
 24→ */
 25→export type ProjectUpdateInput = Prisma.ProjectUncheckedUpdateInput;
 26→
 27→/**
 28→ * Project findMany params type
 29→ */
 30→export type ProjectFindManyParams = {
 31→  where?: Prisma.ProjectWhereInput;
 32→  orderBy?: Prisma.ProjectOrderByWithRelationInput;
 33→  skip?: number;
 34→  take?: number;
 35→  include?: Prisma.ProjectInclude;
 36→};
 37→
 38→/**
 39→ * Repository for Project CRUD operations
 40→ */
 41→export class ProjectRepository {
 42→  /**
 43→   * Find many projects with optional filtering
 44→   * Automatically filters out soft-deleted records
 45→   */
 46→  async findMany(params?: ProjectFindManyParams): Promise<Project[]> {
 47→    const { where, ...rest } = params ?? {};
 48→
 49→    return prisma.project.findMany({
 50→      ...rest,
 51→      where: {
 52→        ...where,
 53→        deletedAt: null, // Always exclude soft-deleted
 54→      },
 55→    });
 56→  }
 57→
 58→  /**
 59→   * Find a single project by ID
 60→   * Returns null if not found or soft-deleted
 61→   */
 62→  async findUnique(
 63→    id: string,
 64→    include?: Prisma.ProjectInclude
 65→  ): Promise<Project | null> {
 66→    return prisma.project.findFirst({
 67→      where: { id, deletedAt: null },
 68→      include,
 69→    });
 70→  }
 71→
 72→  /**
 73→   * Find projects by status
 74→   */
 75→  async findByStatus(status: string): Promise<Project[]> {
 76→    return this.findMany({
 77→      where: { status },
 78→      orderBy: { createdAt: 'desc' },
 79→    });
 80→  }
 81→
 82→  /**
 83→   * Find projects by manager (owner)
 84→   */
 85→  async findByManager(managerId: string): Promise<Project[]> {
 86→    return this.findMany({
 87→      where: { managerId },
 88→      orderBy: { createdAt: 'desc' },
 89→    });
 90→  }
 91→
 92→  /**
 93→   * Find projects by contact
 94→   */
 95→  async findByContact(contactId: string): Promise<Project[]> {
 96→    return this.findMany({
 97→      where: { contactId },
 98→      orderBy: { createdAt: 'desc' },
 99→    });
100→  }
101→
102→  /**
103→   * Find projects by deal
104→   */
105→  async findByDeal(dealId: string): Promise<Project[]> {
106→    return this.findMany({
107→      where: { dealId },
108→      orderBy: { createdAt: 'desc' },
109→    });
110→  }
111→
112→  /**
113→   * Create a new project
114→   * Generates UUID and timestamps if not provided
115→   */
116→  async create(data: ProjectCreateInput): Promise<Project> {
117→    const now = new Date();
118→
119→    return prisma.project.create({
120→      data: {
121→        ...data,
122→        id: data.id ?? randomUUID(),
123→        externalNumber: data.externalNumber ?? this.generateExternalNumber(),
124→        createdAt: data.createdAt ?? now,
125→        updatedAt: data.updatedAt ?? now,
126→      },
127→    });
128→  }
129→
130→  /**
131→   * Generate external project number in format PRJ-YYYY-NNNNN
132→   */
133→  private generateExternalNumber(): string {
134→    const year = new Date().getFullYear();
135→    const random = Math.floor(Math.random() * 99999).toString().padStart(5, '0');
136→    return `PRJ-${year}-${random}`;
137→  }
138→
139→  /**
140→   * Update an existing project
141→   * Throws Error if project doesn't exist or is soft-deleted
142→   */
143→  async update(
144→    id: string,
145→    data: ProjectUpdateInput
146→  ): Promise<Project> {
147→    // Verify project exists and not deleted
148→    const existing = await this.findUnique(id);
149→    if (!existing) {
150→      throw new Error(`Project with id ${id} not found`);
151→    }
152→
153→    return prisma.project.update({
154→      where: { id },
155→      data: {
156→        ...data,
157→        updatedAt: new Date(),
158→      },
159→    });
160→  }
161→
162→  /**
163→   * Soft delete a project by setting deletedAt timestamp
164→   * Does NOT actually delete the record from database
165→   */
166→  async softDelete(id: string): Promise<Project> {
167→    // Verify project exists and not already deleted
168→    const existing = await this.findUnique(id);
169→    if (!existing) {
170→      throw new Error(`Project with id ${id} not found`);
171→    }
172→
173→    return prisma.project.update({
174→      where: { id },
175→      data: { deletedAt: new Date() },
176→    });
177→  }
178→
179→  /**
180→   * Count projects matching criteria (excluding soft-deleted)
181→   */
182→  async count(where?: Prisma.ProjectWhereInput): Promise<number> {
183→    return prisma.project.count({
184→      where: {
185→        ...where,
186→        deletedAt: null,
187→      },
188→    });
189→  }
190→
191→  /**
192→   * Create a project stage
193→   */
194→  async createStage(
195→    projectId: string,
196→    data: Omit<Prisma.ProjectStageUncheckedCreateInput, 'id' | 'projectId'>
197→  ): Promise<ProjectStage> {
198→    return prisma.projectStage.create({
199→      data: {
200→        ...data,
201→        id: randomUUID(),
202→        projectId,
203→      },
204→    });
205→  }
206→
207→  /**
208→   * Update a project stage
209→   */
210→  async updateStage(
211→    stageId: string,
212→    data: Prisma.ProjectStageUncheckedUpdateInput
213→  ): Promise<ProjectStage> {
214→    return prisma.projectStage.update({
215→      where: { id: stageId },
216→      data,
217→    });
218→  }
219→
220→  /**
221→   * Find stages for a project
222→   */
223→  async findStages(projectId: string): Promise<ProjectStage[]> {
224→    return prisma.projectStage.findMany({
225→      where: { projectId },
226→      orderBy: { order: 'asc' },
227→    });
228→  }
229→
230→  /**
231→   * Add a member to a project
232→   */
233→  async addMember(
234→    projectId: string,
235→    userId: string,
236→    role: string = 'member'
237→  ): Promise<ProjectMember> {
238→    return prisma.projectMember.create({
239→      data: {
240→        id: randomUUID(),
241→        projectId,
242→        userId,
243→        role,
244→        joinedAt: new Date(),
245→      },
246→    });
247→  }
248→
249→  /**
250→   * Remove a member from a project (sets leftAt timestamp)
251→   */
252→  async removeMember(projectId: string, userId: string): Promise<ProjectMember> {
253→    const member = await prisma.projectMember.findUnique({
254→      where: { projectId_userId: { projectId, userId } },
255→    });
256→
257→    if (!member) {
258→      throw new Error(`Member ${userId} not found in project ${projectId}`);
259→    }
260→
261→    return prisma.projectMember.update({
262→      where: { projectId_userId: { projectId, userId } },
263→      data: { leftAt: new Date() },
264→    });
265→  }
266→
267→  /**
268→   * Find members for a project
269→   */
270→  async findMembers(projectId: string): Promise<ProjectMember[]> {
271→    return prisma.projectMember.findMany({
272→      where: {
273→        projectId,
274→        leftAt: null, // Only active members
275→      },
276→      include: {
277→        User: {
278→          select: {
279→            id: true,
280→            name: true,
281→            email: true,
282→          },
283→        },
284→      },
285→    });
286→  }
287→}
288→
289→/**
290→ * Singleton instance for use across the application
291→ */
292→export const projects = new ProjectRepository();
293→
294→export default projects;
295→

